    top_k: int = 5
) -> List[SearchResult]:
    """Search in an index and apply metadata filters to results.

    Args:
        index_path: Path to the LEANN index file
        query: Search query string
        metadata_filters: Optional filters to apply to metadata.
            Format: {"field_name": {"operator": value}}
            Supported operators:
            - Comparison: "==", "!=", "<", "<=", ">", ">="
            - Membership: "in", "not_in"
        top_k: Number of nearest neighbors to return (default: 5)

    Returns:
        Filtered list of SearchResult objects
    """
    # Validate index file exists
    path = Path(index_path)
    if not path.exists():
        raise FileNotFoundError(f"LEANN index file not found at {index_path}")

    # Initialize searcher
    searcher = LeannSearcher(index_path=index_path)

    # Handle case where no filters specified
    if metadata_filters is None:
        metadata_filters = {}

    # Perform search with top_k
    results = searcher.search(query, top_k=top_k)

    # Apply metadata filters
    filtered_results = []
    for result in results:
        passes_all_filters = True
        for field, filter_spec in metadata_filters.items():
            if field not in result.metadata:
                passes_all_filters = False
                break
            operator = list(filter_spec.keys())[0]
            expected_value = filter_spec[operator]

            # Handle different operators
            actual_value = result.metadata[field]
            if operator == "==":
                if actual_value != expected_value:
                    passes_all_filters = False
                    break
            elif operator == "!=":
                if actual_value == expected_value:
                    passes_all_filters = False
                    break
            elif operator == "<":
                if not isinstance(actual_value, (int, float)) or actual_value >= expected_value:
                    passes_all_filters = False
                    break
            elif operator == "<=":
                if not isinstance(actual_value, (int, float)) or actual_value > expected_value:
                    passes_all_filters = False
                    break
            elif operator == ">":
                if not isinstance(actual_value, (int, float)) or actual_value <= expected_value:
                    passes_all_filters = False
                    break
            elif operator == ">=":
                if not isinstance(actual_value, (int, float)) or actual_value < expected_value:
                    passes_all_filters = False
                    break
            elif operator == "in":
                if actual_value not in expected_value:
                    passes_all_filters = False
                    break
            elif operator == "not_in":
                if actual_value in expected_value:
                    passes_all_filters = False
                    break
            else:
                # Invalid operator, skip this result
                passes_all_filters = False
                break

        if passes_all_filters:
            filtered_results.append(result)

    return filtered_results

