def verify_index_integrity(index_path: str) -> dict[str, Any]:
    meta_path = f"{index_path}.meta.json"
    if not Path(meta_path).exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    with open(meta_path, encoding="utf-8") as f:
        meta = json.load(f)
    passage_count = meta.get("passage_count", 0)

    passage_manager = PassageManager()
    passage_manager.load_meta(meta_path)

    errors = []
    passages_file = f"{index_path}.passages.txt"
    ids_file = f"{index_path}.ids.txt"

    def _check_file(file_path: str, expected: int, desc: str) -> None:
        if not Path(file_path).exists():
            errors.append(f"{desc} file missing: {file_path}")
        else:
            try:
                with open(file_path, encoding="utf-8") as f:
                    actual = len(f.readlines())
                if actual != expected:
                    errors.append(f"{desc} count mismatch: expected {expected}, got {actual}")
            except Exception as e:
                errors.append(f"Error reading {desc} file: {e}")

    _check_file(passages_file, passage_count, "Passages")
    _check_file(ids_file, passage_count, "IDs")

    try:
        passages = passage_manager.get_passages()
        if len(passages) != passage_count:
            errors.append(
                f"Loaded passage count ({len(passages)}) doesn't match meta ({passage_count})"
            )
    except Exception as e:
        errors.append(f"Error loading passages from meta: {e}")

    return {
        "is_valid": len(errors) == 0,
        "passage_count": passage_count,
        "metadata_file_exists": True,
        "errors": errors
    }

