def get_index_statistics(index_path: str) -> dict[str, Any]:
    try:
        pm = PassageManager(index_path=index_path)
    except FileNotFoundError:
        raise FileNotFoundError("Index metadata file not found")

    fields = set()
    field_value_counts = defaultdict(Counter)
    total = 0

    for passage_source in pm.passage_sources:
        with open(passage_source) as f:
            for line_num, line in enumerate(f, 1):
                passage = json.loads(line.strip())
                metadata = passage.get('metadata', {})
                total += 1
                # Collect all fields present in this passage
                for field in metadata:
                    fields.add(field)
                # Update counts for each field
                for field in fields:
                    value = metadata.get(field)
                    if value is not None:
                        field_value_counts[field][value] += 1

    return {
        "total_passages": total,
        "metadata_fields": sorted(list(fields)),
        "field_value_counts": {k: dict(v) for k, v in field_value_counts.items()}
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> dict[str, Any]:
    try:
        pm = PassageManager(index_path=index_path)
    except FileNotFoundError:
        raise FileNotFoundError("Index metadata file not found")

    total = 0
    covered = 0
    field_presence = defaultdict(int)
    present_fields = set()

    for passage_source in pm.passage_sources:
        with open(passage_source) as f:
            for line_num, line in enumerate(f, 1):
                passage = json.loads(line.strip())
                metadata = passage.get('metadata', {})
                total += 1
                # Check if all required fields are present
                if all(field in metadata for field in required_fields):
                    covered += 1
                # Track presence of each required field
                for field in required_fields:
                    if field in metadata:
                        field_presence[field] += 1
                        present_fields.add(field)

    coverage_percentage = (covered / total) * 100 if total != 0 else 0.0
    field_coverage = {field: (field_presence[field] / total) * 100 for field in required_fields}
    missing_fields = [field for field in required_fields if field not in present_fields]

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": missing_fields
    }

